import { TrainStatus } from './types';
import { getTrainStatus, updateTrainStatus, FOOD_STOP_STATION, MOCK_STATIONS } from './mockDb';

// Haversine distance formula (returns km)
export function haversineDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
    const R = 6371;
    const dLat = ((lat2 - lat1) * Math.PI) / 180;
    const dLng = ((lng2 - lng1) * Math.PI) / 180;
    const a =
        Math.sin(dLat / 2) ** 2 +
        Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLng / 2) ** 2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

// Simulate progressive train movement on the route
let _tick = 0;
const ROUTE_SEGMENTS = [
    { fromIdx: 0, toIdx: 1, tickStart: 0, tickEnd: 20 },   // NDLS -> MTJ
    { fromIdx: 1, toIdx: 2, tickStart: 20, tickEnd: 35 },  // MTJ -> AGC
    { fromIdx: 2, toIdx: 3, tickStart: 35, tickEnd: 50 },  // AGC -> GWL
    { fromIdx: 3, toIdx: 4, tickStart: 50, tickEnd: 65 },  // GWL -> JHS
    { fromIdx: 4, toIdx: 5, tickStart: 65, tickEnd: 100 }, // JHS -> BPL (food stop)
    { fromIdx: 5, toIdx: 6, tickStart: 100, tickEnd: 115 },
    { fromIdx: 6, toIdx: 7, tickStart: 115, tickEnd: 140 },
    { fromIdx: 7, toIdx: 8, tickStart: 140, tickEnd: 160 },
    { fromIdx: 8, toIdx: 9, tickStart: 160, tickEnd: 175 },
    { fromIdx: 9, toIdx: 10, tickStart: 175, tickEnd: 200 },
];

function interpolate(from: number, to: number, progress: number): number {
    return from + (to - from) * progress;
}

export function simulateTrainMovement(): TrainStatus {
    _tick = (_tick + 1) % 200;

    // Find current segment
    const seg = ROUTE_SEGMENTS.find(s => _tick >= s.tickStart && _tick < s.tickEnd)
        || ROUTE_SEGMENTS[ROUTE_SEGMENTS.length - 1];

    const progress = ((_tick - seg.tickStart) / (seg.tickEnd - seg.tickStart));
    const fromSt = MOCK_STATIONS[seg.fromIdx];
    const toSt = MOCK_STATIONS[seg.toIdx];

    const currentLat = interpolate(fromSt.lat, toSt.lat, progress);
    const currentLng = interpolate(fromSt.lng, toSt.lng, progress);
    const distanceToStop = haversineDistance(currentLat, currentLng, FOOD_STOP_STATION.lat, FOOD_STOP_STATION.lng);

    // Simulate delay every ~80 ticks
    const delayMinutes = _tick > 75 && _tick < 85 ? 20 : 0;
    const status = delayMinutes > 0 ? 'DELAYED' : (_tick >= 195 ? 'ARRIVED' : 'ON_TIME');

    // ETA based on remaining distance at 100km/h average
    const etaHours = distanceToStop / 100;
    const eta = new Date(Date.now() + etaHours * 3600 * 1000).toISOString();

    const updated: Partial<TrainStatus> = {
        currentStation: fromSt.name,
        currentStationCode: fromSt.code,
        nextStation: toSt.name,
        nextStationCode: toSt.code,
        currentLat,
        currentLng,
        delayMinutes,
        status,
        speed: delayMinutes > 0 ? 0 : 110 + Math.round(Math.random() * 20),
        distanceToStop: Math.max(0, distanceToStop),
        eta,
    };

    updateTrainStatus(updated);
    return getTrainStatus();
}

export function getPNRStatus(pnr: string) {
    // Returns train status + PNR info linked
    return { trainStatus: getTrainStatus(), pnr };
}

export const PREP_TRIGGER_DISTANCE_KM = 30; // km from stop station to trigger prep
export const HOLD_DELAY_THRESHOLD_MIN = 15; // minutes delay to trigger hold
